from llama_stack_client import LlamaStackClient

class SafeAgentLoop:
    def __init__(self, client, safety_threshold=0.7, max_turns=10):
        self.client = client
        self.safety_threshold = safety_threshold
        self.turns = 0
        self.max_turns = max_turns

    def step(self):
        if self.turns >= self.max_turns:
            return {'content': 'Max turns reached - safety shutdown'}

        response = self.client.agent_loop_step()
        safety_score = response.get('safety_metadata', {}).get('score', 1.0)

        if safety_score < self.safety_threshold:
            return {'content': f'Safety violation detected (score: {safety_score}) - conversation terminated'}

        self.turns += 1
        return response

safe_loop = SafeAgentLoop(client)
